#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        while (1) {
            int min1 = -1, min2 = -1;
            for (int i = 0; i < n; i++) {
                if (arr[i] > k && (min1 == -1 || arr[i] < arr[min1])) {
                    min2 = min1;
                    min1 = i;
                } else if (arr[i] > k && (min2 == -1 || arr[i] < arr[min2])) {
                    min2 = i;
                }
            }
            if (min1 == -1 || min2 == -1) break;
            arr[min1]--;
            arr[min2]--;
        }
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += arr[i];
        }
        printf("%d\n", sum);
    }
    return 0;
}

