import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }
            while (true) {
                int min1 = -1, min2 = -1;
                for (int i = 0; i < n; i++) {
                    if (arr[i] > k && (min1 == -1 || arr[i] < arr[min1])) {
                        min2 = min1;
                        min1 = i;
                    } else if (arr[i] > k && (min2 == -1 || arr[i] < arr[min2])) {
                        min2 = i;
                    }
                }
                if (min1 == -1 || min2 == -1) break;
                arr[min1]--;
                arr[min2]--;
            }
            int sum = 0;
            for (int i = 0; i < n; i++) {
                sum += arr[i];
            }
            System.out.println(sum);
        }
    }
}

